// AddResource.js - Form to add or edit a resource

import { useState, useEffect } from "react";

// Initial blank form state
const emptyForm = {
  title: "",
  type: "PDF",
  semester: "1",
  category: "Notes",
  description: "",
};

export default function AddResource({ onAdd, onUpdate, onCancel, editingResource }) {
  const [form, setForm] = useState(emptyForm);
  const isEditing = !!editingResource;

  // If editing, pre-fill the form with the existing resource data
  useEffect(() => {
    if (editingResource) {
      setForm({
        title: editingResource.title,
        type: editingResource.type,
        semester: editingResource.semester,
        category: editingResource.category,
        description: editingResource.description,
      });
    } else {
      setForm(emptyForm);
    }
  }, [editingResource]);

  // Update form fields on change
  function handleChange(e) {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  }

  // Submit the form
  function handleSubmit(e) {
    e.preventDefault();

    // Basic validation
    if (!form.title.trim() || !form.description.trim()) {
      alert("Please fill in all fields.");
      return;
    }

    if (isEditing) {
      // Pass updated data along with original ID and metadata
      onUpdate({
        ...editingResource,
        ...form,
      });
    } else {
      // For new resources, let the parent add the ID and metadata
      onAdd(form);
    }
  }

  return (
    <div className="add-resource-section">
      <div className="form-container">
        <h2>{isEditing ? "Edit Resource" : "Add a New Resource"}</h2>
        <form onSubmit={handleSubmit} className="resource-form">
          <div className="form-group">
            <label htmlFor="title">Title *</label>
            <input
              type="text"
              id="title"
              name="title"
              value={form.title}
              onChange={handleChange}
              placeholder="e.g., Data Structures Notes"
              required
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="type">Type *</label>
              <select
                id="type"
                name="type"
                value={form.type}
                onChange={handleChange}
              >
                <option value="PDF">PDF</option>
                <option value="Book">Book</option>
                <option value="Physical">Physical Item</option>
                <option value="Link">Link</option>
              </select>
            </div>

            <div className="form-group">
              <label htmlFor="semester">Semester *</label>
              <select
                id="semester"
                name="semester"
                value={form.semester}
                onChange={handleChange}
              >
                <option value="1">1</option>
                <option value="2">2</option>
                <option value="3">3</option>
                <option value="4">4</option>
                <option value="5">5</option>
                <option value="6">6</option>
                <option value="7">7</option>
                <option value="8">8</option>
              </select>
            </div>

            <div className="form-group">
              <label htmlFor="category">Category *</label>
              <select
                id="category"
                name="category"
                value={form.category}
                onChange={handleChange}
              >
                <option value="Notes">Notes</option>
                <option value="Books">Books</option>
                <option value="Question Bank">Question Bank</option>
                <option value="Equipment">Equipment</option>
                <option value="Other">Other</option>
              </select>
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="description">Description *</label>
            <textarea
              id="description"
              name="description"
              value={form.description}
              onChange={handleChange}
              placeholder="Describe the resource, condition, availability, etc..."
              rows="4"
              required
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="btn-submit">
              {isEditing ? "Update Resource" : "Add Resource"}
            </button>
            {isEditing && (
              <button
                type="button"
                className="btn-cancel"
                onClick={onCancel}
              >
                Cancel
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
}
